const stages = {
  1: 'Before Morning',
  2: 'Morning Commute',
  3: 'Workday',
  4: 'Decision Room',
  5: 'The Day Repeats',
  6: 'Twilight: The Wider Landscape',
  7: 'Midnight Ledger',
  8: 'New Dawn'
}

function score(totalHint) {
  const presets = {
    35: [5, 5, 5, 5, 5, 5, 5],
    34: [5, 5, 5, 5, 5, 4, 5],
    33: [5, 4, 5, 5, 5, 4, 5],
    32: [4, 5, 5, 5, 5, 4, 4],
    31: [4, 4, 5, 5, 5, 4, 4],
    30: [4, 4, 4, 5, 5, 4, 4],
    29: [4, 4, 4, 4, 5, 4, 4],
    28: [4, 4, 4, 4, 4, 4, 4],
    27: [4, 4, 4, 4, 4, 3, 4],
    26: [4, 3, 4, 4, 4, 3, 4],
    25: [3, 4, 4, 4, 4, 3, 3],
    24: [3, 3, 4, 4, 4, 3, 3]
  }
  return presets[totalHint] ?? presets[28]
}

function brief(row) {
  const scores = score(row.score ?? 28)
  const totalScore = scores.reduce((sum, value) => sum + value, 0)
  return {
    version: VERSION,
    stageNumber: row.stage,
    stageTitle: stages[row.stage],
    learningCardNumber: row.card,
    learningCardId: row.cardId,
    learningCardTitle: row.cardTitle,
    currentVisualId: row.visualId,
    currentVisualTitle: row.visualTitle,
    currentVisualType: row.visualType,
    currentVisualQualityRating: row.quality,
    currentIssueSummary: row.issue,
    oneSentenceLearningObjective: row.objective,
    oneConceptVisualMustConvey: row.concept,
    misconceptionVisualMustCorrect: row.misconception,
    selectedCanonicalTemplate: row.template,
    selectedCanonicalTemplateId: visualAidTemplates.find((template) => template.name === row.template)?.id,
    whyThisTemplateFits: row.why,
    exactLabelsAllowedInsideVisual: row.labels,
    calloutsBelowVisual: row.callouts,
    altText: row.alt,
    image2Allowed: row.image2Allowed,
    image2Prompt: row.image2Prompt ?? '',
    codedLayoutSketch: row.codedLayout ?? '',
    mobileRiskNotes: row.mobileRisk,
    priorityBefore: row.before,
    priority: row.after,
    status: row.status,
    notesForHumanTesters: row.testerNotes,
    mustRemainCodedSvgHtml: row.mustRemainCoded,
    internalLabelCountEstimate: row.internalLabels ?? row.labels.length,
    screenshot390: `docs/journey/screenshots/v0-28-3/${row.visualId}-390.png`,
    scores: {
      fiveSecondClarity: scores[0],
      mobileReadability: scores[1],
      singleIdeaFocus: scores[2],
      mechanismAccuracy: scores[3],
      captionCalloutSupport: scores[4],
      styleConsistency: scores[5],
      misconceptionRepair: scores[6],
      total: totalScore
    },
    recommendation: row.recommendation ?? (row.after === 'P3' ? 'Keep for human testing.' : 'Accept for small human testing; improve in a later visual-design pass.')
  }
}

