export function summarizeReadiness(briefs = visualAidReadinessBriefs) {
  const countBy = (field) => briefs.reduce((counts, brief) => {
    counts[brief[field]] = (counts[brief[field]] ?? 0) + 1
    return counts
  }, {})
  return {
    version: VERSION,
    total: briefs.length,
    priorityBeforeCounts: countBy('priorityBefore'),
    priorityAfterCounts: countBy('priority'),
    templateDistribution: countBy('selectedCanonicalTemplate'),
    statusDistribution: countBy('status'),
    visualTypeDistribution: countBy('currentVisualType'),
    p0p1Remaining: briefs.filter((brief) => ['P0', 'P1'].includes(brief.priority)).map((brief) => brief.currentVisualId),
    fixedVisuals: briefs.filter((brief) => brief.status === 'fixed').map((brief) => brief.currentVisualTitle),
    temporaryVisuals: briefs.filter((brief) => brief.status === 'temporary').map((brief) => brief.currentVisualTitle),
    laterImage2: briefs.filter((brief) => brief.image2Allowed).map((brief) => brief.currentVisualTitle),
    mustRemainCoded: briefs.filter((brief) => brief.mustRemainCodedSvgHtml).map((brief) => brief.currentVisualTitle),
    topWatchList: [...briefs].sort((a, b) => a.scores.total - b.scores.total).slice(0, 10).map((brief) => ({
      visual: brief.currentVisualTitle,
      card: brief.learningCardTitle,
      score: brief.scores.total,
      priority: brief.priority,
      whyWatch: brief.mobileRiskNotes
    }))
  }
}
